mapper.select:
select pa.id as aircraftId, pa.tail_number as tailNumber, pa.msn, pa.registration_number as registrationNumber, pa.aircraft_type as aircraftType, pa.operational_status as operationalStatus, pa.total_fh as totalFh, pa.total_fc as totalFc, am.id as modelId, am.model_code as modelCode, am.name as modelName from t1_physical_aircraft pa left join t1_ac_model am on am.id = pa.model_id
pa.model_id = #{modelId}
order by pa.tail_number

mapper.update:
update t1_dossier_version
set content_hash = #{contentHash}
where id = #{versionId}
  and (content_hash is null or content_hash = '')

mapper.select:
select id from t1_document_category
name = #{categoryName}
order by sort_order, id limit 1
